using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "An MCP server that exposes application configuration as resources and tools for querying settings.";
})
.WithHttpTransport()
.WithToolsFromAssembly()
.WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();                                // Streamable HTTP at /mcp
app.MapGet("/health", () => "ok");           // Health check for orchestrators

app.Run();

