+using System.ComponentModel;
+using System.Text.Json;
+using ModelContextProtocol.Server;
+
+[McpServerToolType]
+public static class ConfigTools
+{
+    [McpServerTool(ReadOnly = true),
+     Description("Search configuration settings whose keys contain the given substring.")]
+    public static string SearchSettings(
+        [Description("Substring to match against setting keys (case-insensitive).")] string query)
+    {
+        var matches = new Dictionary<string, string>
+        {
+            ["app:name"]        = "ConfigMcpServer",
+            ["app:version"]     = "1.0.0",
+            ["app:environment"] = "Production",
+            ["feature:darkMode"] = "true",
+            ["feature:betaApi"]  = "false"
+        }
+        .Where(kv => kv.Key.Contains(query, StringComparison.OrdinalIgnoreCase))
+        .ToDictionary(kv => kv.Key, kv => kv.Value);
+
+        return matches.Count > 0
+            ? JsonSerializer.Serialize(matches, new JsonSerializerOptions { WriteIndented = true })
+            : $"No settings matched '{query}'.";
+    }
+}
+

