 using System.ComponentModel;
 using System.Text.Json;
 using ModelContextProtocol.Server;

 [McpServerResourceType]
 public static class ConfigResource
 {
     private static readonly Dictionary<string, string> Settings = new()
     {
         ["app:name"]        = "ConfigMcpServer",
         ["app:version"]     = "1.0.0",
         ["app:environment"] = "Production",
         ["feature:darkMode"] = "true",
         ["feature:betaApi"]  = "false"
     };

     /// <summary>
     /// Returns all application settings as a JSON object.
     /// Clients read this via: config://app/settings
     /// </summary>
     [McpServerResource(
         UriTemplate = "config://app/settings",
         Name = "Application Settings",
         MimeType = "application/json"),
      Description("All application configuration settings as key-value pairs.")]
     public static string GetAllSettings() =>
         JsonSerializer.Serialize(Settings, new JsonSerializerOptions { WriteIndented = true });

     /// <summary>
     /// Returns a single setting by key.
     /// Clients read this via: config://app/settings/{key}
     /// </summary>
     [McpServerResource(
         UriTemplate = "config://app/settings/{key}",
         Name = "Setting by Key",
         MimeType = "text/plain"),
      Description("A single configuration value looked up by key.")]
     public static string GetSetting(string key) =>
         Settings.TryGetValue(key, out var value) ? value : $"Unknown setting: {key}";
 }

